template.script:
{
  "@context": "https://schema.org",
  "@graph": [
    {
      "@type": "Organization",
      "@id": "/#organization",
      "name": "BhuKhadan",
      "url": "",
      "logo": "/bhukhadan_web/static/src/img/bhuarjan_logo.png",
      "description": "Coal Bearing Areas land acquisition management under CBA(A&D) Act 1957.",
      "contactPoint": {
        "@type": "ContactPoint",
        "telephone": "+91-70420-38092",
        "contactType": "customer support",
        "email": "support@bhuarjan.com",
        "availableLanguage": ["English", "Hindi"]
      }
    },
    {
      "@type": "WebSite",
      "@id": "/#website",
      "url": "",
      "name": "BhuKhadan",
      "publisher": {"@id": "/#organization"},
      "inLanguage": "en-IN"
    },
    {
      "@type": "ItemList",
      "name": "BhuKhadan Site Navigation",
      "itemListElement": [
        {"@type": "SiteNavigationElement", "position": 1, "name": "Home", "url": "/"},
        {"@type": "SiteNavigationElement", "position": 2, "name": "Features", "url": "/features"},
        {"@type": "SiteNavigationElement", "position": 3, "name": "Mobile App", "url": "/mobile-app"},
        {"@type": "SiteNavigationElement", "position": 4, "name": "Acts Covered", "url": "/acts"},
        {"@type": "SiteNavigationElement", "position": 5, "name": "Contact Us", "url": "/contact"}
      ]
    }
  ]
}
